def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        complexity = 0
        if ratio > 10:
            complexity = (ratio - 10) ** 4
            for a in range(5, 0, -1):
                for b in range(1, a + 5):
                    weight = (ratio - a) / (b + 1) * np.sin(ratio * b / a)
                    complexity += weight ** 2
            priority = np.tanh(complexity) * 20 + np.exp(-ratio / 2) * 15
        elif 6 < ratio <= 10:
            complexity = 0
            for p in range(1, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    term = np.log1p(abs(ratio - p)) * np.cos(ratio * q)
                    complexity += np.sin(term) / (q + 0.5)
            priority = complexity * 12 + np.sqrt(ratio) * 8 - np.exp(-ratio / 3) * 5
        elif 3 <= ratio <= 6:
            s = 0
            for r in range(1, 15):
                power_term = ((ratio - 3) ** r) / (r * 2.5)
                s += power_term * np.sin(ratio * r * 0.8) * np.cos(r)
            priority = s + np.tanh(ratio) * 10 - np.log1p(ratio * 3)
        elif 1 <= ratio < 3:
            s = 0
            for x in range(1, 20):
                val = np.exp(-x / 5) * np.cos(x * ratio)
                s += ((3 - ratio) ** x) * val / (x + 1)
            penalty = 0
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item * bin_cap) * 5
            else:
                penalty = np.cos(15 * ratio) * 3
            priority = s + penalty + np.sin(ratio * i) * 7
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 25):
                s += ((1 - ratio) ** n) / (n ** 2 + 1) * np.sin(n * ratio * 2)
            if (i + int(item * 2)) % 5 == 0:
                factor = np.log1p(bin_cap + 5) * 1.7
            else:
                factor = 1 / (np.sqrt(bin_cap) + 3)
            priority = s * factor + np.exp(-ratio) * 12 - np.tanh(i / (ratio + 0.1))
        elif 0.2 <= ratio < 0.5:
            s = 0
            for m in range(1, 18):
                s += ((0.5 - ratio) ** m) / (m * 5) * np.cos(m * item * 1.3)
            priority = s + np.log1p(bin_cap) * 4
            if bin_cap < item * 0.3:
                priority += np.sqrt(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 3) * 7
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 0.7)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 2.3) % 7 == 0:
                priority *= 3.5
            else:
                priority /= 2.7
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 4) * 5
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 7
            for _ in range(3):
                priority += np.sin(ratio * np.random.uniform(0, 10)) * 0.8
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 6
            for factor in range(2, 6):
                if (i * factor) % 5 == 0:
                    priority += np.cos(ratio * factor * i) * 0.5
                else:
                    priority -= np.sin(ratio * factor * i) * 0.5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.3) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.1) * 0.4
        if i % 2 == 0:
            priority += np.sin(ratio * i * 1.7) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.7) * 0.7
        fluctuation = 0
        for f in range(1, 5):
            fluctuation += ((-1) ** (f + i)) * np.sin(f * ratio * (i + 2)) / (f + 0.3)
        priority += fluctuation
        if ratio % 1 < 0.1:
            priority *= 1.2
        elif ratio % 1 > 0.9:
            priority *= 0.8
        priorities[i] = priority
    return priorities
